mapper.select:
SELECT /* PayInfoMapper.orgPayInfoList */ A.KFTC_EVIDENCE_SEQ as kftcevidenceseq /*증거파일 SEQ */ , A.rgst_dt as rgstdt/*등록일자*/ , A.valid_dt as validdt/*유효일자*/ , B.contract_num as contractnum /*계약번호*/ , B.ban /*청구계정번호*/ , B.SUBSCRIBER_NO AS telno /*전화번호*/ , B.SUB_LINK_NAME AS custname /*고객명*/ , B.sub_status as substatus /*상태*/ , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS substatusnm /*상태명*/ , B.lst_com_actv_date as lstcomactvdate/*가입일자*/ , B.open_agnt_cd as openagntcd /*대리점코드*/ , B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openagntnm /*대리점명*/ , A.regst_id as regstid/*등록자ID*/ , A.regst_dttm as regstdttm/*등록일자*/ , A.rvisn_id as rvisnid /*수정자ID*/ , A.rvisn_dttm as rvisndttm/*수정일자*/ , A.real_file_path as realfilepath /*실 파일경로*/ , A.real_file_nm as realfilenm /*실 파일명*/ , NVL(A.REG_YN, 'N') AS reg_yn /*파일 등록 여부*/ , DECODE(NVL(A.REG_YN, 'N'), 'N' ,'미등록', '등록') AS regynnm /*파일 등록 여부*/ , A.EXT /*파일 확장자*/ , B.SUB_ADR_PRIMARY_LN AS addr /*고객주소*/ , SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ')), 1,6) AS userssn /*생년월일*/ , C.bl_billing_method as blbillingmethod /*납부방법코드*/ , FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS bl_billingmethodnm /*납부방법명*/ , B.on_off_type as onofftype /*온오프라인구분*/ , FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS onofftypenm /*온오프라인구분명*/ , A.approval_id as approvalid/*검증자ID*/ , FN_GET_USRNM(A.APPROVAL_ID) AS approvalidnm /*검증자명*/ , A.approval_msg as approvalmsg /*검증내역*/ , TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS approvaldt /*검증일시*/ , NVL(A.APPROVAL_CD, '0002') AS approvalcd /*검증결과*/ , FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS approvalcdnm /*검증결과명*/ , NVL(A.EVIDENCE_TYPE_CD, '0002') AS evidencetypecd /*파일유형*/ , FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS evicdnm /*파일유형명*/ FROM CMN_KFTC_EVIDENCE A, MSP_JUO_SUB_INFO B, MSP_JUO_BAN_INFO C WHERE B.CONTRACT_NUM = A.CONTRACT_NUM(+) AND B.BAN = C.BAN(+) AND B.PPPO = 'PO'
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (B.CONTRACT_NUM = #{searchName} OR B.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUBSCRIBER_NO = #{searchName}
AND NVL(A.REG_YN, 'N') = #{regYn}
AND B.LST_COM_ACTV_DATE BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.RGST_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND A.VALID_DT BETWEEN #{searchStartDt} AND #{searchEndDt}
AND B.OPEN_AGNT_CD = #{orgnId}
ORDER BY B.LST_COM_ACTV_DATE DESC

SELECT /* PayInfoMapper.selectPayinfoKtEx */ A.KFTC_MST_SEQ as kftcmstseq , /*payinfo mst seq */ A.kftc_dtl_seq as kftcdtlseq, /*payinfo dtl seq */ A.bill_acnt_no as billacntno, /*(전문)청구계정번호 */ A.contract_num as contractnum, /* 가입계약번호 */ A.subscriber_no as subscriberno, /*전화번호 이전CTN */ A.sub_link_name as sublinkname, /*사용자이름*/ A.agre_mngm_no as agremngmno, /*(전문)동의관리번호 */ SUBSTR(A.RGST_DT, 1,8) AS rgstdt, /* (전문)등록일자 */ A.agre_type_cd as agretype_d, /* (전문)동의구분코드 */ A.sls_cmpn_cd as slscmpncd, /*(전문)사업자코드 */ A.bank_cd as bankcd, /*(전문)은행코드 */ FN_GET_CODENM('CMN0001', NVL(A.BANK_CD, '001')) AS bankcdnm, /*은행명 */ A.cms_aply_srl_no as cmsaplysrlno, /*(전문)CMS등록일련번호 */ A.outpym_srl_no as outpymsrlno, /*(전문)출금일련번호 */ A.bank_bnkacn_no as bankbnkacnno, /*(전문)계좌번호 */ A.real_file_name as realfilename, /*수신 or 서식지파일명 */ A.real_file_dir as realfiledir, /* 동의파일full path*/ A.error_cd as errorcd, /*(전문)오류코드 */ FN_GET_CODENM('CMN0207', NVL(A.ERROR_CD, '0002')) AS errorcdnm, /* 에러명*/ A.ready_cd as readycd, /*실파일송신준비코드 */ A.send_cd as sendcd, /* 송신코드*/ A.regst_id as regstid, /* 등록자ID*/ A.regst_dttm as regstdttm, /*등록일시 */ A.rvisn_id as rvisnid, /* 승인자ID*/ A.rvisn_dttm as rvisndttm, /*일인일자*/ B.sub_status as substatus, /*승인사유 */ FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS substatusnm, /* 가입자상태명*/ B.lst_com_actv_date as lstcomactvdate, /* 최초개통일자*/ B.open_agnt_cd as openagntcd, /* 개통대리점코드*/ B.OPEN_AGNT_CD || ' / ' ||FN_GET_ORGNM(B.OPEN_AGNT_CD) AS openagntnm, /* 개통대리점*/ A.file_reg_yn as fileregyn, /* 증거파일등록여부코드*/ DECODE(NVL(A.FILE_REG_YN, 'N'), 'N' ,'미등록', '등록') AS fileregynnm,/*증거파일등록여부명 */ B.SUB_ADR_PRIMARY_LN AS addr, /* 주소*/ SUBSTR(CRYPTO_AES256.DEC_AES(NVL(B.USER_SSN, ' ' )), 1,6) AS userssn, /*주민번호 */ C.bl_billing_method as blbillingmethod, /* 납부방법*/ FN_GET_CODENM('MSP0001', NVL(C.BL_BILLING_METHOD, '0001')) AS blbillingmethodnm, B.on_off_type as onofftype, /* 개통방법*/ FN_GET_CODENM('RCP0007', NVL(B.ON_OFF_TYPE, '1')) AS onofftypenm , /* 개통방법명*/ A.approval_id as approvalid, /*검증자ID*/ FN_GET_USRNM(A.APPROVAL_ID) AS approvalidnm, /*검증자명*/ A.approval_msg as approvalmsg, /*검증내역*/ TO_CHAR(A.APPROVAL_DT, 'YYYY-MM-DD HH24:MI:SS') AS approvaldt, /*검증일시*/ NVL(A.APPROVAL_CD, '0002') AS approvalcd, /*검증결과*/ FN_GET_CODENM('CMN0211', NVL(A.APPROVAL_CD, '0002')) AS approvalcdnm, /*검증결과명*/ NVL(A.EVIDENCE_TYPE_CD, '0002') AS evidencetypecd, /*파일유형*/ FN_GET_CODENM('CMN0210', NVL(A.EVIDENCE_TYPE_CD, '0002')) AS evicdnm /*파일유형명*/ FROM CMN_KFTC_BATCH_DTL A , MSP_JUO_SUB_INFO B , MSP_JUO_BAN_INFO C , CMN_KFTC_BATCH_MST D WHERE 1=1 AND A.KFTC_MST_SEQ = D.KFTC_MST_SEQ AND D.STATE_CD != '0050' AND A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.BILL_ACNT_NO = C.BAN(+)
AND A.KFTC_MST_SEQ = #{kftcMstSeq}
AND A.RGST_DT BETWEEN #{searchStartDt}||'000000' AND #{searchEndDt}||'235959'
AND A.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND A.SUBSCRIBER_NO = #{searchName}
AND A.FILE_REG_YN = #{fileRegYn}
AND B.OPEN_AGNT_CD = #{orgnId}
